     * given a specific threshold.
     *
     * @param n The number of nodes.
     * @param edges The list of edges [u, v, w].
     * @param source The starting node.
     * @param target The destination node.
     * @param k The maximum allowed heavy edges.
     * @param threshold The threshold weight.
     * @return true if a valid path exists, false otherwise.
     */
    private static boolean canReach(int n, int[][] edges, int source, int target, int k, int threshold) {
        if (source == target) return true;

        // Adjacency list: stores pairs of [neighbor, cost_type]
        // cost_type: 0 for light (w <= threshold), 1 for heavy (w > threshold)
        List<List<int[]>> adj = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }

        for (int[] edge : edges) {
            int u = edge[0];
            int v = edge[1];
            int w = edge[2];
            int costType = (w <= threshold) ? 0 : 1;

            // Undirected graph
            adj.get(u).add(new int[]{v, costType});
            adj.get(v).add(new int[]{u, costType});
        }

        // BFS/Dijkstra-like approach: state is (node, heavy_edges_used)
        // dist[i][j] = minimum number of edges to reach node i using exactly j heavy edges.
        // Since we only care about reachability given a constraint, we can use BFS
        // on the state space (node, heavy_edges_used).

        // dist[i][j] stores boolean: is node i reachable using exactly j heavy edges?
        // We use a simpler approach: queue stores {node, heavy_count}

        Queue<int[]> queue = new LinkedList<>();
        // visited[node][heavy_count] = true if this state has been processed
        boolean[][] visited = new boolean[n][k + 1];

        queue.offer(new int[]{source, 0});
        visited[source][0] = true;

        while (!queue.isEmpty()) {
            int[] current = queue.poll();
            int u = current[0];
            int heavyCount = current[1];

            if (u == target) {
                return true;
            }

            for (int[] neighborInfo : adj.get(u)) {
                int v = neighborInfo[0];
                int costType = neighborInfo[1]; // 0=light, 1=heavy

                int newHeavyCount = heavyCount + costType;

                if (newHeavyCount <= k && !visited[v][newHeavyCount]) {
                    visited[v][newHeavyCount] = true;
                    queue.offer(new int[]{v, newHeavyCount});
                }
            }
        }

        return false;
    }

