import java.util.*;

class Solution {
    /**
     * Checks if there is a path from source to target using at most k heavy edges 
     * for a given threshold.
     * @param n Number of nodes.
     * @param edges List of all edges.
     * @param source Source node.
     * @param target Target node.
     * @param k Maximum allowed heavy edges.
     * @param threshold The current threshold.
     * @return true if a valid path exists, false otherwise.
     */
    private static boolean canReach(int n, List<int[]> edges, int source, int target, int k, int threshold) {
        // dist[i][j] stores the minimum number of heavy edges required to reach node i from node j
        // Since we are looking for the minimum number of heavy edges, we can use a modified BFS/Dijkstra.
        // The state in our search will be (node, heavy_edges_count).

        // dist[i] stores the minimum number of heavy edges to reach node i from source.
        // Initialize with infinity (k + 1 is effectively infinity for this problem)
        int[] minHeavyEdges = new int[n];
        Arrays.fill(minHeavyEdges, k + 1);

        // Priority Queue for Dijkstra-like approach: {heavy_count, node}
        // We prioritize fewer heavy edges.
        PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a -> a[0]));

        minHeavyEdges[source] = 0;
        pq.offer(new int[]{0, source}); // {heavy_count, node}

        while (!pq.isEmpty()) {
            int[] current = pq.poll();
            int currentHeavyCount = current[0];
            int u = current[1];

            if (currentHeavyCount > minHeavyEdges[u]) {
                continue;
            }

            if (u == target) {
                // We found a path to target, and since we are using Dijkstra, this is the path 
                // with the minimum heavy edges among all paths explored so far.
                return currentHeavyCount <= k;
            }

            // Iterate over all edges to find neighbors
            for (int[] edge : edges) {
                int u1 = edge[0];
                int v1 = edge[1];
                int w1 = edge[2];

                int neighbor = -1;
                if (u1 == u) {
                    neighbor = v1;
                } else if (v1 == u) {
                    neighbor = u1;
                } else {
                    continue; // Edge doesn't involve u
                }

                // Determine if the edge (u, neighbor) is heavy or light based on threshold
                int isHeavy = (w1 > threshold) ? 1 : 0;

                int newHeavyCount = currentHeavyCount + isHeavy;

                if (newHeavyCount <= k && newHeavyCount < minHeavyEdges[neighbor]) {
                    minHeavyEdges[neighbor] = newHeavyCount;
                    pq.offer(new int[]{newHeavyCount, neighbor});
                }
            }
        }

        return minHeavyEdges[target] <= k;
    }

    public static long solve(long n, long[][] edges, long source, long target, long k) {
        if (source == target) {
            return 0;
        }

        int N = (int) n;
        int K = (int) k;

        // Collect all unique edge weights to form the search space for the threshold.
        // The optimal threshold must be one of the edge weights or -1 if no path exists.
        Set<Integer> uniqueWeights = new HashSet<>();
        for (long[] edge : edges) {
            uniqueWeights.add((int) edge[2]);
        }

        // The set of candidate thresholds to check: all unique weights, plus 0 (since weights >= 1).
        // If the optimal threshold is smaller than the minimum weight, it behaves like threshold = -1 (all edges are heavy, 
        // but we are looking for the smallest *integer* threshold).
        // If all weights are W_i, checking W_i and W_i-1 covers the transition points.

        List<Integer> candidates = new ArrayList<>();
        candidates.add(0); // Minimum possible threshold
        for (int w : uniqueWeights) {
            candidates.add(w);
            if (w > 0) {
                candidates.add(w - 1);
            }
        }

        // Sort and deduplicate candidates
        candidates = new ArrayList<>(new HashSet<>(candidates));
        Collections.sort(candidates);

        // Binary Search on the possible range of thresholds
        // The range is [0, max_weight] or potentially slightly higher if needed, 
        // but checking all candidates is safer given the discrete nature of the problem.

        // Find the smallest candidate threshold that works.
        int minThreshold = -1;

        for (int threshold : candidates) {
            if (threshold < 0) continue;

            // Check reachability for the current threshold
            if (canReach(N, new ArrayList<int[]>(edges), (int) source, (int) target, K, threshold)) {
                minThreshold = threshold;
                // Since candidates are sorted, the first one that works is the minimum.
                break;
            }
        }

        // Edge case: If the optimal threshold is greater than the maximum edge weight, 
        // it means all edges are light, and the path exists if any path exists in the graph.
        // We must check the largest possible weight.
        if (minThreshold == -1 && !uniqueWeights.isEmpty()) {
             int maxW = Collections.max(uniqueWeights);
             if (canReach(N, new ArrayList<int[]>(edges), (int) source, (int) target, K, maxW)) {
                 // This case should ideally be covered by checking maxW, but for robustness:
                 // If maxW works, and nothing smaller worked, maxW is the answer, 
                 // unless we need an even larger threshold, which is impossible as all edges would be light.
                 minThreshold = maxW;
             }
        }

        return minThreshold;
    }
}
